// src/components/PlayerPicker.js
// ─────────────────────────────────────────────────────────────
// Shown when a player has no stored session token.
// They enter the short code that was shared with them.
// ─────────────────────────────────────────────────────────────

import React, { useState } from 'react';
import { usePlayerIdentity } from '../context/PlayerIdentityContext';
import ThemeToggle from './shared/ThemeToggle';

function PlayerPicker({ leagueName, sport }) {
  const { loginWithToken } = usePlayerIdentity();
  const [token,   setToken]   = useState('');
  const [error,   setError]   = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async () => {
    if (!token.trim()) return;
    setLoading(true);
    setError('');
    try {
      await loginWithToken(token.trim());
      // On success, PlayerIdentityContext updates currentPlayer
      // and the parent (Dashboard) renders the actual app
    } catch (err) {
      setError(err.message || 'Invalid code. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="wizard-card">
      <div className="card-accent" />

      <div className="card-header">
        <div className="card-header-top">
          <div>
            <div className="brand">Ladder League</div>
            <div className="step-indicator">Identify Yourself</div>
          </div>
          <ThemeToggle />
        </div>
      </div>

      <div className="card-body">
        {leagueName && (
          <div className="league-name-banner" style={{ marginBottom: '1.5rem' }}>
            <span className="league-name-text">{leagueName}</span>
          </div>
        )}

        <div className="field-group">
          <label>Your Player Code</label>
          <input
            type="text"
            className="player-token-input"
            placeholder="Enter the code shared with you…"
            value={token}
            onChange={(e) => { setToken(e.target.value); setError(''); }}
            onKeyDown={(e) => e.key === 'Enter' && handleSubmit()}
            autoFocus
            autoCapitalize="none"
            autoCorrect="off"
            spellCheck={false}
          />
          <div className="field-hint">
            Your league admin shared a unique code with you via text or email.
            Enter it here to access your league.
          </div>
        </div>

        {error && (
          <div className="picker-error">⚠ {error}</div>
        )}

        <div className="picker-help">
          <div className="picker-help-title">Don't have a code?</div>
          <div className="picker-help-body">
            Contact your league admin — they can find your code in the
            Admin panel under player settings.
          </div>
        </div>
      </div>

      <div className="card-footer">
        <button
          className="btn-next"
          onClick={handleSubmit}
          disabled={!token.trim() || loading}
        >
          {loading ? 'Checking…' : 'Enter League →'}
        </button>
      </div>
    </div>
  );
}

export default PlayerPicker;
